 export async function processPayment(payment: Payment): Promise<boolean> {
-  logger.info("processPayment", { amount: payment.amount });
-  return true;
+  // New: synchronous HTTP call to an external fraud-detection microservice
+  const resp = await fetch(`${FRAUD_SERVICE_URL}/check`, {
+    method: "POST",
+    headers: { "Content-Type": "application/json" },
+    body: JSON.stringify({ amount: payment.amount, userId: payment.userId }),
+    signal: AbortSignal.timeout(3000),
+  });
